179	
180	    bool fun_name_is_key = false;       // In JSON format function name is JSON key, i.e. { "<funname>": { ... arguments ... } }
181	    bool tools_array_wrapped = false;   // Tool calls wrapped in JSON array [...]
182	
183	    std::string              function_field = "function";
