197	struct tool_arguments_analysis {
198	    std::string start;          // e.g., "<|tool_call_argument_begin|>", "<args>"
199	    std::string end;            // e.g., "<|tool_call_argument_end|>", "</args>"
200	    std::string name_prefix;   // e.g., "<param=", "<arg_key>", "\""
201	    std::string name_suffix;   // e.g., ">", "</arg_key>", "\":"
202	    std::string value_prefix;  // e.g., "", "<arg_value>", ""
203	    std::string value_suffix;  // e.g., "</param>", "</arg_value>", ""
204	    std::string separator;     // e.g., "", "\n", ","
205	};
206	
