struct common_chat_params {
    common_chat_format                  format = COMMON_CHAT_FORMAT_CONTENT_ONLY;
    std::string                         prompt;                    // Final rendered prompt
    std::string                         grammar;                   // GBNF grammar string
    bool                                grammar_lazy = false;      // Lazy grammar generation
    std::string                         generation_prompt;         // Prompt suffix before generation
    bool                                supports_thinking = false; // Can model emit reasoning?
    std::string                         thinking_start_tag;        // e.g., "[THINK]", "<think>"
    std::string                         thinking_end_tag;          // e.g., "[/THINK]", "</think>"
    std::vector<common_grammar_trigger> grammar_triggers;          // When to apply grammar
    std::vector<std::string>            preserved_tokens;          // Tokens to protect from generation
    std::vector<std::string>            additional_stops;          // Extra stop sequences
    std::string                         parser;                    // Serialized PEG parser
};
